mapper.insert:
/* SmsCommonMapper.insertMsgQueue */
INSERT INTO MSG_QUEUE 
(
	MSEQ

	    ,MSG_TYPE


	    ,DSTADDR


	    ,CALLBACK


	    ,SUBJECT


	    ,STAT


	    ,TEXT_TYPE


	    ,TEXT


	    ,EXPIRETIME


	    ,REQUEST_TIME


	    ,OPT_ID


	    ,TEXT2


	    ,K_TEMPLATE_CODE


	    ,K_NEXT_TYPE


	    ,SENDER_KEY

) VALUES (
	SMS_SEQ.NEXTVAL

	    ,#{msgType}


	    ,#{mobileNo}


	    ,#{sendNumber}


	    ,#{subject}


	    ,#{stat}


	    ,#{textType}


	    ,#{sendMessage}


	    ,#{expireTime}


	    ,TO_DATE(#{requestTime}, 'YYYYMMDDHH24MISS')


	    ,#{optId}


	    ,#{text2}


	    ,#{kTemplateCode}


	    ,#{kNextType}


	    ,#{senderKey}

)


	SELECT AM2X_SUBMIT_SEQ.NEXTVAL AS msgId
	FROM   DUAL

/* SmsCommonMapper.insertKtMsgQueue */
INSERT INTO AM2X_SUBMIT 
(
	MSG_ID

	    ,SUBJECT


	    ,MSG_TYPE


	    ,MSG_TYPE_SECOND


	    ,MSG_TYPE_THIRD

	    ,SCHEDULE_TIME
	    ,SUBMIT_TIME

	    ,MESSAGE


	    ,CALLBACK_NUM


	    ,RCPT_DATA


	    ,FILE_COUNT


	    ,FILE_NAME1


	    ,FILE_NAME2


	    ,FILE_NAME3


	    ,CDR_ID


	    ,FAIL_SEND


	    ,K_TMPLCODE


	    ,K_MESSAGE


	    ,K_BUTTON


	    ,K_ADFLAG


	    ,K_SENDERKEY


	    ,R_MESSAGEBASEID


	    ,R_BODY


	    ,R_BUTTON


	    ,R_HEADER


	    ,R_FOOTER


	    ,R_COPYALLOWED


	    ,R_QUERYID


	    ,RESERVED01


	    ,RESERVED02


	    ,RESERVED03


	    ,KISA_ORIG_CODE


	    ,R_AGENCYID


	    ,R_AGENCYKEY


	    ,R_BRANDKEY


	    ,R_CDR_ID


) VALUES (
	#{msgId}

	    ,#{subject}


	    ,DECODE(#{msgType}, '3', '2', #{msgType})


	    ,#{msgTypeSecond}


	    ,#{msgTypeThird}


		 ,#{scheduleTime} 
		,TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') 


		 ,#{submitTime} 
		,TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') 


	    ,#{message}


	    ,#{callbackNum}


	    ,#{rcptData}


	    ,#{fileCount}


	    ,#{fileName1}


	    ,#{fileName2}


	    ,#{fileName3}


	    ,#{cdrId}


	    ,#{failSend}


	    ,#{kTmplcode}


	    ,#{kMessage}


	    ,#{kButton}


	    ,#{kAdflag}


	    ,#{kSenderkey}


	    ,#{rMessagebaseid}


	    ,#{rBody}


	    ,#{rButton}


	    ,#{rHeader}


	    ,#{rFooter}


	    ,#{rCopyallowed}


	    ,#{rQueryid}


	    ,#{reserved01}


	    ,#{reserved02}


	    ,#{reserved03}


	    ,#{kisaOrigCode}


	    ,#{rAgencyid}


	    ,#{rAgencykey}


	    ,#{rBrandkey}


	    ,#{rCdrId}

)

SELECT AM2X_SUBMIT_SEQ.NEXTVAL AS msgId ,NVL(#{scheduleTime}, TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') ) AS scheduleTime FROM DUAL
/* SmsMgmtMapper.insertKtMsgTmpQueue */ INSERT INTO AM2X_SUBMIT ( MSG_ID /* Sequence */ ,MSG_TYPE /* 1=SMS 2=LMS 3=MMS 6=A_KAKAO */ ,FAIL_SEND /* 실패시 재 발송 여부(카카오 실패일 경우 발송)*/ ,RCPT_DATA /* 수신자 번호 */ ,CALLBACK_NUM /* 발신자 번호 */ ,SUBJECT /* 제목 */ ,MESSAGE /* 전송메시지 */ ,SCHEDULE_TIME /* 발송요청시간 */ ,SUBMIT_TIME /* 등록시간 */ ,RESERVED01 /* MSP */ ,RESERVED02 /* SMS TEMPLATE ID */ ,RESERVED03 /* 발송자,발송화면 */ ,K_MESSAGE /* 카카오 실패 시 대체발송 메세지 */ ,K_TMPLCODE /* 카카오 알림톡 템플릿 코드 */ ,MSG_TYPE_SECOND /* 카카오 실패 시 대체발송 메세지 타입 1=SMS 2=LMS 3=MMS */ ,K_SENDERKEY /* 카카오 발신프로필키 */ ) SELECT #{msgId}
, '6', 'Y' ,DECODE(MSG_TYPE, '3', '2', MSG_TYPE), 'N'
,#{rcptData} ,CALLBACK ,NVL( #{subject}, SUBJECT ) ,NVL( #{message}, TEXT ) ,#{scheduleTime} ,TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') ,#{reserved01} ,#{reserved02} ,#{reserved03}
,NVL( #{kMessage}, TEXT ) , ''
,NVL( K_TEMPLATE_CODE, '') ,NVL( #{msgTypeSecond}, 0) ,NVL( #{kSenderkey}, '') FROM MSP_SMS_TEMPLATE_MST WHERE TEMPLATE_ID = #{templateId}

/* SmsMgmtMapper.insertKtSmsSendMst */
INSERT INTO MSP_SMS_RESEND_MST (
	 SEND_SEQ			/* 일련번호	*/
	,TEMPLATE_ID		/* SMS Template ID */
	,MSG_ID				/* SMS일련번호 */
	,SEND_REQ_DTTM		/* 발송요청일시 */
	,REGST_ID			/* 등록자ID */
	,REGST_DTTM			/* 등록일시 */
	,RVISN_ID			/* 수정자ID */
	,RVISN_DTTM			/* 수정일시 */
)
VALUES (
	 SMS_RESEND_SEQ.NEXTVAL
	,#{templateId}
	,#{msgId}
	,#{sendReqDttm}
	,#{reqId}
	,SYSDATE
	,#{reqId}
	,SYSDATE
)

mapper.select:
/* SmsMgmtMapper.getKtTemplateText */
SELECT text AS templateText
	  ,subject AS templateSubject
	  ,k_template_code as kTmplcode
FROM   MSP_SMS_TEMPLATE_MST
WHERE  TEMPLATE_ID = #{templateId}

mapper.insert:
/* SmsCommonMapper.insertSmsSendMst */
INSERT INTO MSP_SMS_SEND_MST (
	 SEND_SEQ			/* 일련번호	*/
	,SEND_DIVISION		/* 발송구분(MCP:홈페이지,MSP:가입고객,USR:M전산사용자,REQ:신청고객) */
	,CONTRACT_NUM		/* 계약번호 */
	,PORTAL_USER_ID		/* 홈페이지사용자ID */
	,MSP_USER_ID		/* M전산사용자ID */
	,RES_NO				/* 예약등록_예약번호 */
	,TEMPLATE_ID		/* SMS Template ID */
	,MSEQ				/* SMS일련번호 */
	,SEND_REQ_DTTM		/* 발송요청일시 */
	,REGST_ID			/* 등록자ID */
	,REGST_DTTM			/* 등록일시 */
	,RVISN_ID			/* 수정자ID */
	,RVISN_DTTM			/* 수정일시 */
	,KT_SMS_YN			/* KT SMS 여부 */
)
VALUES (
	 SMS_SEND_SEQ.NEXTVAL
	,#{sendDivision}
	,#{contractNum}
	,#{portalUserId}
	,#{mspUserId}
	,#{resNo}
	,#{templateId}
	,#{mseq}
	,#{requestTime}
	,#{reqId}
	,SYSDATE
	,#{reqId}
	,SYSDATE
	,#{ktSmsYn}
)

mapper.update:
/* SmsCommonMapper.updateSmsSendMst */
UPDATE  MSP_SMS_RESEND_MST
SET     SEND_CNT = SEND_CNT + 1
      , MSG_ID = #{msgId}
      , SEND_REQ_DTTM = #{scheduleTime}
      , RVISN_ID = #{reqId}
      , RVISN_DTTM = SYSDATE
WHERE   SEND_SEQ = #{sendSeq}

mapper.select:
/* SmsMgmtMapper.getTemplateText */
SELECT text AS templateText
	  ,subject AS templateSubject
	  ,k_template_code as kTemplateCode
FROM   MSP_SMS_TEMPLATE_MST
WHERE  TEMPLATE_ID = #{templateId}

mapper.insert:
SELECT SMS_SEQ.NEXTVAL AS mseq ,NVL(#{requestTime}, TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') ) AS requestTime FROM DUAL
/* SmsCommonMapper.insertTemplateMsgQueue */ INSERT INTO MSG_QUEUE ( MSEQ /* Sequence */ ,MSG_TYPE /* 1:SMS 2:SMS URL 3:MMS 4:MMS URL 6:kakao*/ ,DSTADDR /* 수신자 번호 */ ,CALLBACK /* 발신자 번호 */ ,SUBJECT /* 제목 */ ,TEXT /* 전송메시지 */ ,EXPIRETIME /* 유효시간 */ ,REQUEST_TIME /* 발송요청시간 */ ,OPT_ID /* SMS TEMPLATE ID */ ) SELECT #{mseq}
,'6' ,MSG_TYPE
,#{mobileNo} ,CALLBACK ,NVL( #{subject}, SUBJECT ) ,NVL( #{sendMessage}, TEXT ) ,EXPIRE_HOUR * 60 * 60 ,TO_DATE(#{requestTime}, 'YYYYMMDDHH24MISS') ,TEMPLATE_ID
FROM MSP_SMS_TEMPLATE_MST WHERE TEMPLATE_ID = #{templateId}

SELECT SMS_SEQ.NEXTVAL AS mseq ,NVL(#{requestTime}, TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') ) AS requestTime FROM DUAL
/* SmsCommonMapper.insertTemplateMsgQueue */ INSERT INTO MSG_QUEUE ( MSEQ /* Sequence */ ,MSG_TYPE /* 1:SMS 2:SMS URL 3:MMS 4:MMS URL 6:kakao*/ ,DSTADDR /* 수신자 번호 */ ,CALLBACK /* 발신자 번호 */ ,SUBJECT /* 제목 */ ,TEXT /* 전송메시지 */ ,EXPIRETIME /* 유효시간 */ ,REQUEST_TIME /* 발송요청시간 */ ,OPT_ID /* SMS TEMPLATE ID */ ,TEXT2 /* 카카오 실패 시 대체발송 메세지 */ ,K_TEMPLATE_CODE /* 카카오 알림톡 템플릿 코드 */ ,K_NEXT_TYPE /* 카카오 실패 시 대체발송 메세지 타입 7:SMS, 8:LMS, 9:MMS */ ,SENDER_KEY /* 카카오 발신프로필키 */ ) SELECT #{mseq}
,'6' ,MSG_TYPE
,#{mobileNo} ,CALLBACK ,NVL( #{subject}, SUBJECT ) ,NVL( #{sendMessage}, TEXT ) ,EXPIRE_HOUR * 60 * 60 ,TO_DATE(#{requestTime}, 'YYYYMMDDHH24MISS') ,TEMPLATE_ID ,NVL( #{sendMessage}, TEXT ) ,NVL( K_TEMPLATE_CODE, '') ,NVL( #{kNextType}, '') ,NVL( #{senderKey}, '')
FROM MSP_SMS_TEMPLATE_MST WHERE TEMPLATE_ID = #{templateId}
